async function main() {
  console.log("Seeding v2 ingredient expansion...");
  const slugsSeen = new Set<string>();
  let added = 0, skipped = 0;

  for (const ing of EXTRA2) {
    if (slugsSeen.has(ing.slug)) { skipped++; continue; }
    slugsSeen.add(ing.slug);

    const existing = await prisma.ingredient.findUnique({ where: { slug: ing.slug } });
    if (existing) { skipped++; continue; }

    const cat = await prisma.ingredientCategory.findUnique({ where: { slug: ing.categorySlug } });
    if (!cat) { console.warn(`  ⚠ No category '${ing.categorySlug}' for ${ing.name}`); skipped++; continue; }

    await prisma.ingredient.create({
      data: {
        slug: ing.slug, name: ing.name, aliases: ing.aliases, eNumber: ing.eNumber,
        categoryId: cat.id, purposeShort: ing.purposeShort, purpose: ing.purpose,
        benefits: ing.benefits, concerns: ing.concerns, sciConsensus: ing.sciConsensus,
        evidenceLevel: ing.evidenceLevel, fdaStatus: ing.fdaStatus, efsaStatus: ing.efsaStatus,
        fssaiStatus: ing.fssaiStatus, whoStatus: ing.whoStatus, safetyScore: ing.safetyScore,
        commonProducts: ing.commonProducts, adiValue: ing.adiValue,
        isNatural: ing.isNatural, isVegan: ing.isVegan,
      }
    });
    added++;
  }

  console.log(`Done: ${added} added, ${skipped} skipped. Total now: ${await prisma.ingredient.count()}`);
  await prisma.$disconnect();
}

main().catch((e) => { console.error(e); prisma.$disconnect(); process.exit(1); });
